const config = $('Configurar grupo').first().json;

const grupoId = String(config.grupo_id || '').trim();
const sessao = String(config.sessao_waha || 'whats_junior').trim();
const telefone = String(config.telefone_divulgacao || '11913022278').replace(/\D/g, '');
const maximo = Math.max(1, Number(config.maximo_vagas_por_mensagem || 5));

if (!grupoId || !grupoId.endsWith('@g.us') || grupoId.startsWith('COLE_AQUI')) {
  throw new Error('Abra o node "Configurar grupo" e informe o ID real do grupo, terminando em @g.us.');
}

const contato = telefone.length === 11
  ? `(${telefone.slice(0, 2)}) ${telefone.slice(2, 7)}-${telefone.slice(7)}`
  : telefone;

const formatarSalario = (valor) => {
  const numero = Number(valor);
  if (!Number.isFinite(numero) || numero <= 0) return 'A combinar';
  return new Intl.NumberFormat('pt-BR', { style: 'currency', currency: 'BRL' }).format(numero);
};

const formatarPercentual = (valor) => {
  const numero = Number(valor);
  if (!Number.isFinite(numero)) return '';
  return new Intl.NumberFormat('pt-BR', { maximumFractionDigits: 2 }).format(numero) + '%';
};

const beneficios = (valor) => {
  const texto = String(valor || '').trim();
  if (!texto) return 'Informados no processo seletivo';
  return texto.split(/\r?\n|;|\|/)
    .map((item) => item.trim().replace(/^[-•*]\s*/, ''))
    .filter(Boolean)
    .slice(0, 4)
    .join(', ');
};

const vagas = items.map((item) => item.json).filter((vaga) => vaga && (vaga.titulo || vaga.cargo));
if (!vagas.length) return [];

const blocos = vagas.map((vaga, indice) => {
  const titulo = String(vaga.titulo || vaga.cargo || 'Vaga disponível').trim();
  const local = String(vaga.bairro || [vaga.cidade, vaga.estado].filter(Boolean).join(' - ') || 'Local a combinar').trim();
  const escala = String(vaga.escala || 'A confirmar').trim();
  const horario = String(vaga.horario || 'A confirmar').trim();
  const insalubridade = vaga.possui_insalubridade === true || String(vaga.possui_insalubridade).toLowerCase() === 'true';
  const percentual = formatarPercentual(vaga.percentual_insalubridade);
  const salario = Number(vaga.salario);
  const percentualNumero = Number(vaga.percentual_insalubridade);
  const adicional = insalubridade && Number.isFinite(salario) && Number.isFinite(percentualNumero)
    ? formatarSalario(salario * (percentualNumero / 100))
    : '';

  return [
    `*${indice + 1}. ${titulo} | Início imediato*`,
    `📍 Bairro: ${local}`,
    `📅 Escala: ${escala}`,
    `⏰ Horário: ${horario}`,
    `💰 Salário: ${formatarSalario(vaga.salario)}`,
    insalubridade ? `🧪 Insalubridade: ${percentual || 'percentual a confirmar'}${adicional ? ` — adicional aproximado de ${adicional}` : ''}` : '',
    `🎁 Benefícios: ${beneficios(vaga.beneficios)}`,
  ].filter(Boolean).join('\n');
});

const saidas = [];
for (let inicio = 0; inicio < blocos.length; inicio += maximo) {
  const parte = blocos.slice(inicio, inicio + maximo);
  const numeroParte = Math.floor(inicio / maximo) + 1;
  const totalPartes = Math.ceil(blocos.length / maximo);
  const cabecalho = totalPartes > 1
    ? `📢 *VAGAS DISPONÍVEIS — PARTE ${numeroParte}/${totalPartes}*`
    : '📢 *VAGAS DISPONÍVEIS*';
  const texto = [cabecalho, '', ...parte.flatMap((bloco) => [bloco, '']), `📲 Para mais informações, chame no privado: ${contato}`].join('\n').trim();
  saidas.push({ json: { session: sessao, chatId: grupoId, text: texto } });
}
return saidas;
